import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';

import HomePage from './components/HomePage';

import ChatBot from './components/ChatBot';
import './App.css';

function App() {
  return (
    <Router>
      <div className="App">
        <Navbar />
        <Routes>
          <Route path="/" element={<HomePage />} />
         
        </Routes>
        <ChatBot />
      </div>
    </Router>
  );
}

export default App;
